export function* iterateBfs(root: IConstruct) {
  // Use a specialized queue data structure. Using `Array.shift()`
  // has a huge performance penalty (difference on the order of
  // ~50ms vs ~1s to iterate a large construct tree)
  const queue = new LinkedQueue<{ construct: IConstruct; parent: IConstruct | undefined }>([{ construct: root, parent: undefined }]);

  let next = queue.shift();
  while (next) {
    for (const child of next.construct.node.children) {
      queue.push({ construct: child, parent: next.construct });
    }
    yield next;

    next = queue.shift();
  }
}

protected shouldPreventGesture(element: TargetElement, pointerType: string): boolean {
  // Get effective configuration for this pointer type
  const effectiveConfig = this.getEffectiveConfig(
    pointerType as PointerMode,
    this.getBaseConfig(),
  );

  // First check if required keyboard keys are pressed
  if (!this.keyboardManager.areKeysPressed(effectiveConfig.requiredKeys)) {
    return true; // Prevent the gesture if required keys are not pressed
  }

  if (this.preventIf.length === 0) {
    return false; // No prevention rules, allow the gesture
  }

  const activeGestures = this.gesturesRegistry.getActiveGestures(element);

  // Check if any of the gestures that would prevent this one are active
  return this.preventIf.some((gestureName) => activeGestures[gestureName]);
}

export function login(collection: Collection): any {
  async function resolver(_, args, context: Context) {
    const options = {
      collection,
      data: {
        email: args.email,
        password: args.password,
        username: args.username,
      },
      depth: 0,
      req: isolateObjectProperty(context.req, 'transactionID'),
    }

    const result = await loginOperation(options)
    const cookie = generatePayloadCookie({
      collectionAuthConfig: collection.config.auth,
      cookiePrefix: context.req.payload.config.cookiePrefix,
      token: result.token,
    })

    context.headers['Set-Cookie'] = cookie

    if (collection.config.auth.removeTokenFromResponses) {
      delete result.token
    }

    return result
  }

  return resolver
}

export function getPatchInfo (
  patchFileGroups: PatchGroupRecord | undefined,
  pkgName: string,
  pkgVersion: string
): ExtendedPatchInfo | undefined {
  if (!patchFileGroups?.[pkgName]) return undefined

  const exactVersion = patchFileGroups[pkgName].exact[pkgVersion]
  if (exactVersion) return exactVersion

  const satisfied = patchFileGroups[pkgName].range.filter(item => satisfies(pkgVersion, item.version))
  if (satisfied.length > 1) {
    throw new PatchKeyConflictError(pkgName, pkgVersion, satisfied)
  }
  if (satisfied.length === 1) {
    return satisfied[0].patch
  }

  return patchFileGroups[pkgName].all
}

#convertIsolationLevel(clientIsolationLevel: Tx.IsolationLevel | undefined): SqlIsolationLevel | undefined {
  switch (clientIsolationLevel) {
    case undefined:
      return undefined
    case 'ReadUncommitted':
      return 'READ UNCOMMITTED'
    case 'ReadCommitted':
      return 'READ COMMITTED'
    case 'RepeatableRead':
      return 'REPEATABLE READ'
    case 'Serializable':
      return 'SERIALIZABLE'
    case 'Snapshot':
      return 'SNAPSHOT'
    default:
      throw new PrismaClientKnownRequestError(
        `Inconsistent column data: Conversion failed: Invalid isolation level \`${
          clientIsolationLevel satisfies never
        }\``,
        {
          code: 'P2023',
          clientVersion: this.config.clientVersion,
          meta: {
            providedIsolationLevel: clientIsolationLevel,
          },
        },
      )
  }
}

function scanForTurboConfigs(project: Project): Array<string> {
  const paths: Array<string> = [];

  // Check root turbo config
  if (project.projectRoot) {
    const configPath = findTurboConfigInDir(project.projectRoot.workspacePath);
    if (configPath) {
      paths.push(configPath);
    }
  }

  // Check ALL workspaces for turbo configs (not just those with turboConfig already loaded)
  for (const workspace of project.projectWorkspaces) {
    const configPath = findTurboConfigInDir(workspace.workspacePath);
    if (configPath) {
      paths.push(configPath);
    }
  }

  return paths;
}

export class ObjectFieldSuggestion implements ErrorBasicBuilder {
  public isRequired = false
  constructor(
    readonly name: string,
    readonly value: string | SuggestionObjectValue,
  ) {}

  makeRequired() {
    this.isRequired = true
    return this
  }

  write(writer: ErrorWriter): void {
    const {
      colors: { green },
    } = writer.context

    writer.addMarginSymbol(green(this.isRequired ? '+' : '?'))
    writer.write(green(this.name))

    if (!this.isRequired) {
      writer.write(green('?'))
    }

    writer.write(green(`: `))
    if (typeof this.value === 'string') {
      writer.write(green(this.value))
    } else {
      writer.write(this.value)
    }
  }
}

export function throwValidationException({
  args,
  errors,
  errorFormat,
  callsite,
  originalMethod,
  clientVersion,
  globalOmit,
}: ExceptionParams): never {
  const argsTree = buildArgumentsRenderingTree(args)
  for (const error of errors) {
    applyValidationError(error, argsTree, globalOmit)
  }

  const { message, args: renderedArgs } = renderArgsTree(argsTree, errorFormat)

  const messageWithContext = createErrorMessageWithContext({
    message,
    callsite,
    originalMethod,
    showColors: errorFormat === 'pretty',
    callArguments: renderedArgs,
  })

  throw new PrismaClientValidationError(messageWithContext, { clientVersion })
}

export function sanitizeError(error: Error, pathSeparator: string = path.sep) {
  try {
    error = {
      ...JSON.parse(JSON.stringify(error)),
      message: removeAnsiEscapeCodes(error.message),
      stack: removeAnsiEscapeCodes(error.stack),
      cause: error.cause,
      name: error.name,
    };

    // Removes all user paths
    const errorString = cleanPaths(JSON.stringify(error), pathSeparator);

    return JSON.parse(errorString);
  } catch (err: unknown) {
    const message = err instanceof Error ? err.message : String(err);
    return `Sanitization error: ${message}`;
  }
}

export function ObjectIdColumn(options?: ColumnOptions): PropertyDecorator {
    return function (object: Object, propertyName: string) {
        // if column options are not given then create a new empty options
        options ??= {} as ColumnOptions
        options.primary = true
        options.name ??= "_id"

        // create and register a new column metadata
        getMetadataArgsStorage().columns.push({
            target: object.constructor,
            propertyName: propertyName,
            mode: "objectId",
            options: options,
        } as ColumnMetadataArgs)
    }
}

function resourceInCommonStackFor(element: Element, commonStack: Stack): CfnResource {
  const resource: CfnResource = (Stack.isStack(element) ? element.nestedStackResource : element) as CfnResource;
  if (!resource) {
    // see "assertion" in operateOnDependency above
    throw new AssumptionError(lit`UnexpectedValueResourceLooking`, `Unexpected value for resource when looking at ${element}!`);
  }

  const resourceStack = Stack.of(resource);

  // we reached a resource defined in the common stack
  if (commonStack === resourceStack) {
    return resource;
  }

  return resourceInCommonStackFor(resourceStack, commonStack);
}

export function checkWorkingTree({ cwd }: { cwd?: string | URL } = {}) {
  let chain = Promise.resolve();

  chain = chain.then(() => describeRef({ cwd }));

  // wrap each test separately to allow all applicable errors to be reported
  const tests = [
    // prevent duplicate versioning
    chain.then(throwIfReleased),
    // prevent publish of uncommitted changes
    chain.then(mkThrowIfUncommitted({ cwd })),
  ];

  // passes through result of describeRef() to aid composability
  return chain.then((result) => Promise.all(tests).then(() => result));
}

export function applySearchable(
  MikroORMEntity: EntityConstructor<any>,
  fieldOrRelationship: PropertyMetadata | RelationshipMetadata
) {
  let propertyName: string
  let isSearchable: boolean

  if ("fieldName" in fieldOrRelationship) {
    propertyName = fieldOrRelationship.fieldName
    isSearchable = !!fieldOrRelationship.dataType.options?.searchable
  } else {
    propertyName = fieldOrRelationship.name
    isSearchable = fieldOrRelationship.searchable
  }

  if (!isSearchable) {
    return
  }

  Searchable()(MikroORMEntity.prototype, propertyName)
}

save(msg: Message | Message[]): void {
  const messages = Array.isArray(msg) ? msg : [msg]
  if (messages.length === 0) {
    return
  }

  for (const message of messages) {
    try {
      const hash = JSON.stringify(message)
      if (!this.#messagesHash.has(hash)) {
        this.#messagesHash.add(hash)
        this.#messages.push(message)
      }
    } catch (e) {
      // noop: if the message is not serializable, we don't want to deduplicate it
      // It should not happen, but we don't want to fail the whole process
      this.#messages.push(message)
    }
  }
}

async setGeolocation(geolocation?: types.Geolocation): Promise<void> {
  verifyGeolocation(geolocation);
  this._options.geolocation = geolocation;
  // Setting geolocation on the user context automatically applies it to all existing
  // pages in the context in Bidi.
  await this._browser._browserSession.send('emulation.setGeolocationOverride', {
    coordinates: geolocation ? {
      latitude: geolocation.latitude,
      longitude: geolocation.longitude,
      accuracy: geolocation.accuracy,
    } : null,
    userContexts: [this._userContextId()],
  });
}

private _addDiagnostic(rule: DiagnosticRule, message: string, textRange: TextRange) {
    const diagLevel = this._fileInfo.diagnosticRuleSet[rule] as DiagnosticLevel;

    let diagnostic: Diagnostic | undefined;
    switch (diagLevel) {
        case 'error':
        case 'warning':
        case 'information':
            diagnostic = this._fileInfo.diagnosticSink.addDiagnosticWithTextRange(diagLevel, message, textRange);
            break;

        case 'none':
            break;

        default:
            return assertNever(diagLevel, `${diagLevel} is not expected`);
    }

    if (diagnostic) {
        diagnostic.setRule(rule);
    }

    return diagnostic;
}

public constructor(parameters: IDocTableParameters, rows?: ReadonlyArray<DocTableRow>) {
  super(parameters);

  this.header = new DocTableRow({ configuration: this.configuration });
  this._rows = [];

  if (parameters) {
    if (parameters.headerTitles) {
      if (parameters.headerCells) {
        throw new Error(
          'IDocTableParameters.headerCells and IDocTableParameters.headerTitles' +
            ' cannot both be specified'
        );
      }
      for (const cellText of parameters.headerTitles) {
        this.header.addPlainTextCell(cellText);
      }
    } else if (parameters.headerCells) {
      for (const cell of parameters.headerCells) {
        this.header.addCell(cell);
      }
    }
  }

  if (rows) {
    for (const row of rows) {
      this.addRow(row);
    }
  }
}

export async function reportSolutions(
	nextSolutionPromise: Promise<SolutionsStream>,
	solutionHandler: ISolutionHandler
): Promise<void> {
	const nextSolution = await nextSolutionPromise;
	switch (nextSolution.status) {
		case 'Solution':
			await solutionHandler.onSolution(nextSolution.solution);
			await reportSolutions(nextSolution.next, solutionHandler);
			break;
		case 'FinishedNormally':
			await solutionHandler.onFinishedNormally();
			break;
		case 'FinishedWithError':
			await solutionHandler.onFinishedWithError(nextSolution.error);
			break;
	}
}

async function createTelemetryWithExp(
	accessor: ServicesAccessor,
	document: TextDocumentContents,
	headerRequestId: string,
	options?: Partial<GetGhostTextOptions>
): Promise<TelemetryWithExp> {
	const featuresService = accessor.get(ICompletionsFeaturesService);
	const properties: TelemetryProperties = { headerRequestId };
	if (options?.opportunityId) { properties.opportunityId = options.opportunityId; }
	if (options?.selectedCompletionInfo?.text) { properties.completionsActive = 'true'; }
	if (options?.isSpeculative) { properties.reason = 'speculative'; }
	const telemetryData = TelemetryData.createAndMarkAsIssued(properties);
	const telemetryWithExp = await featuresService.updateExPValuesAndAssignments(
		{ uri: document.uri, languageId: document.detectedLanguageId },
		telemetryData
	);
	return telemetryWithExp;
}

function addStoreForFeatureImport(
  tree: Tree,
  isParentStandalone,
  route: string,
  sourceFile: SourceFile,
  parentPath: string,
  provideStoreForFeature: string,
  storeForFeature: string
) {
  if (isParentStandalone) {
    const parentContents = tree.read(parentPath, 'utf-8');
    if (parentContents.includes('ApplicationConfig')) {
      addProviderToAppConfig(tree, parentPath, provideStoreForFeature);
    } else if (parentContents.includes('bootstrapApplication')) {
      addProviderToBootstrapApplication(
        tree,
        parentPath,
        provideStoreForFeature
      );
    } else {
      addProviderToRoute(tree, parentPath, route, provideStoreForFeature);
    }
  } else {
    sourceFile = addImportToModule(
      tree,
      sourceFile,
      parentPath,
      storeForFeature
    );
  }
  return sourceFile;
}

applyDeoptimizations() {
	this.deoptimized = true;
	if (this.variable instanceof LocalVariable) {
		// When accessing a variable from a module without side effects, this
		// means we use an export of that module and therefore need to potentially
		// include it in the bundle.
		if (!this.variable.module.isExecuted) {
			markModuleAndImpureDependenciesAsExecuted(this.variable.module);
		}
		this.variable.consolidateInitializers();
		this.scope.context.requestTreeshakingPass();
	}
	if (this.isVariableReference) {
		this.variable!.addUsedPlace(this);
		this.scope.context.requestTreeshakingPass();
	}
}

export function getComparator<ComparatorName extends keyof ScreenshotComparatorRegistry>(
  comparator: ComparatorName,
  context: BrowserCommandContext,
): Comparator<ScreenshotComparatorRegistry[ComparatorName]> {
  if (comparator in comparators) {
    return comparators[comparator]
  }

  const customComparators = context
    .project
    .config
    .browser
    .expect
    ?.toMatchScreenshot
    ?.comparators

  if (customComparators && comparator in customComparators) {
    return customComparators[comparator]
  }

  throw new Error(`Unrecognized comparator ${comparator}`)
}

export function parseGithubUrl(urlStr: string): ParsedGithubUrl {
  let match;
  for (const pattern of githubPatterns) {
    match = urlStr.match(pattern);
    if (match) {
      break;
    }
  }

  if (!match)
    throw new Error(invalidGithubUrlMessage(urlStr));

  let [, auth, username, reponame, treeish = `master`] = match;

  const {commit} = querystring.parse(treeish) as {commit?: string};

  treeish =
    // New style:
    // The URLs have already been normalized by `gitUtils.resolveUrl`,
    // so it's certain in the context of the `GithubFetcher`
    // that the `commit` querystring parameter exists
    commit
    // Old style:
    // Shouldn't ever be needed by the GithubFetcher
    || treeish.replace(/[^:]*:/, ``);

  return {auth, username, reponame, treeish};
}

isPreviouslyFocusedRow(): boolean {
  if (!this.expandingRow.expandingRowHost.contentRows) {
    return false;
  }

  const expandingRowHost = this.expandingRow.expandingRowHost;

  if (!this.mainElementRef || !expandingRowHost.lastFocusedRow) {
    return false;
  }

  if (!expandingRowHost.lastFocusedRow.summaryViewChild.mainElementRef) {
    return false;
  }

  // If the current expanding row summary was the last focused one before
  // focus exited the list, then return true to trigger the screen reader
  if (
    this.mainElementRef.nativeElement ===
    expandingRowHost.lastFocusedRow.summaryViewChild.mainElementRef.nativeElement
  ) {
    return true;
  }
  return false;
}

export function isAnnotationEvaluationPostponed(fileInfo: AnalyzerFileInfo) {
    if (fileInfo.isStubFile) {
        return true;
    }

    if (fileInfo.futureImports.has('annotations')) {
        return true;
    }

    // As of May 2023, the Python steering council has approved PEP 649 for Python 3.13.
    // It was tentatively approved for 3.12, but they decided to defer until the next
    // release to reduce the risk. As of May 8, 2024, the change did not make it into
    // Python 3.13beta1, so it has been deferred to Python 3.14.
    // https://discuss.python.org/t/pep-649-deferred-evaluation-of-annotations-tentatively-accepted/21331
    if (PythonVersion.isGreaterOrEqualTo(fileInfo.executionEnvironment.pythonVersion, pythonVersion3_14)) {
        return true;
    }

    return false;
}

public verifyParentChildRelationship(parentName: string, childName: string) {
  const parentWidgetSelector =
    anvilLocators.anvilWidgetNameSelector(parentName);
  const childWidgetSelector =
    anvilLocators.anvilWidgetNameSelector(childName);
  // check if childWidgetSelector is inside parentWidgetSelector
  cy.get(parentWidgetSelector).within(() => {
    cy.get(childWidgetSelector);
  });
  // check if there are no other widgets in between parent and child
  cy.get(childWidgetSelector)
    .parentsUntil(parentWidgetSelector, anvilLocators.anvilWidgetSelector)
    .should("have.length", 0);
}

export function disposeEmitNodes(sourceFile: SourceFile | undefined): void {
    // During transformation we may need to annotate a parse tree node with transient
    // transformation properties. As parse tree nodes live longer than transformation
    // nodes, we need to make sure we reclaim any memory allocated for custom ranges
    // from these nodes to ensure we do not hold onto entire subtrees just for position
    // information. We also need to reset these nodes to a pre-transformation state
    // for incremental parsing scenarios so that we do not impact later emit.
    const annotatedNodes = getSourceFileOfNode(getParseTreeNode(sourceFile))?.emitNode?.annotatedNodes;
    if (annotatedNodes) {
        for (const node of annotatedNodes) {
            node.emitNode = undefined;
        }
    }
}

markFieldIncompatible(input: InputDescriptor, incompatibility: FieldIncompatibility) {
  if (!this.knownInputIds.has(input.key)) {
    throw new Error(`Input cannot be marked as incompatible because it's not registered.`);
  }

  const inputInfo = this.knownInputIds.get(input.key)!;
  const existingIncompatibility = inputInfo.container.getInputMemberIncompatibility(input);

  // Ensure an existing more significant incompatibility is not overridden.
  if (existingIncompatibility !== null && isFieldIncompatibility(existingIncompatibility)) {
    incompatibility = pickFieldIncompatibility(existingIncompatibility, incompatibility);
  }

  this.knownInputIds
    .get(input.key)!
    .container.memberIncompatibility.set(input.key, incompatibility);
}

export function makeBumpOnlyFilter(pkg: Package) {
  return (newEntry: string): string => {
    // When force publishing, it is possible that there will be no actual changes, only a version bump.
    if (!newEntry.split("\n").some((line) => line.startsWith("*"))) {
      // Add a note to indicate that only a version bump has occurred.
      // TODO: actually list the dependencies that were bumped
      const message = `**Note:** Version bump only for package ${pkg.name}`;

      // the extra blank lines preserve the whitespace delimiting releases
      return [newEntry.trim(), message, BLANK_LINE].join(BLANK_LINE);
    }

    return newEntry;
  };
}

public constructor(options: IAstDeclarationOptions) {
  this.declaration = options.declaration;
  this.astSymbol = options.astSymbol;
  this.parent = options.parent;

  this.astSymbol._notifyDeclarationAttach(this);

  if (this.parent) {
    this.parent._notifyChildAttach(this);
  }

  this.modifierFlags = ts.getCombinedModifierFlags(this.declaration);

  // Check for ECMAScript private fields, for example:
  //
  //    class Person { #name: string; }
  //
  const declarationName: ts.DeclarationName | undefined = ts.getNameOfDeclaration(this.declaration);
  if (declarationName) {
    if (ts.isPrivateIdentifier(declarationName)) {
      // eslint-disable-next-line no-bitwise
      this.modifierFlags |= ts.ModifierFlags.Private;
    }
  }
}
